INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('4', '4', 'AAST is a processing aid that supports staff in completing administrative tasks for immigration applications, including data-matching and bulk email creation.', 'The modules in question, the Biometric and Medical modules, use index matching of lists of biographical information between the biometric enrolments and immigration medical examinations, and applications pending those assessments. The processing aid does not review the results of the applicant''s immigration medical examinations or biometric enrollment, and only compares basic biographical data to score a level of match.', 'Natural GCMS data points', 'Recommendations on matching assessments to applications', 'Applicants of immigration services');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('5', '5', 'This project seeks to streamline the eligibility assessment for all visitor record applications in order to help IRCC decision-makers process applications more efficiently.', 'The advanced data analytics system identifies routine applications for streamlined processing. When the system finds these applications, it can decide that an applicant is eligible, before sending the file to an officer to decide if the applicant remains admissible to Canada and make the final decision.', 'Personal information', 'The system can automate the approval of the eligibility portion of certain visitor record applications.', 'Applicants of visitor records');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('6', '6', 'Reducing Recalculation Workload through Machine Learning', 'The ML model specifically focuses on terminated or dormant claims and aims to predict the potential outcomes of recalculations.', 'EI production data', 'The model classifies claim recalculations into three categories of outcomes: Increase in benefit rate, Decrease in benefit rate, No Change in benefit rate.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('7', '7', 'Expedite border processing for incoming travellers and minimize border wait times and points of contact.', 'ArriveCAN is a digital platform that is being used to collect travel and COVID-19-related health information from individuals traveling to Canada. By automating the scanning of travellers'' proof of vaccination using Optical Character Recognition (OCR) technology, ArriveCAN augments the government''s capacity to process incoming travellers and enhances its readiness to adapt to the gradual reopening of the border to international travellers.', 'Personal information, Images and videos', 'Scanned proofs of vaccination help inform whether a traveller is eligible to enter Canada and any quarantine or other requirements they may be subject to following their entry.', 'Travellers to Canada');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('8', '8', 'The CUAET program was designed from the beginning to respond urgently to the crisis in Ukraine by streamlining our existing temporary resident process. IRCC will now further enhance efficiency by automating certain checks and actions previously performed by IRCC officers. For CUAET applications, these tasks and activities now include automatically confirming a positive decision and generating a visa if all eligibility and admissibility criteria are met.', 'Process optimization and workflow automation: Analyzing large data sets to identify and anomalies, cluster patterns, predict outcomes or ways to optimize; and automate specific workflows', 'Personal information', 'Automated positive eligibility determinations, positive inadmissibility determinations, and approvals on some temporary resident visa and work permit applications', 'Applicants for Temporary Resident Visas and Work Permits under the CUAET');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('9', '9', NULL, 'Project is to increase our use of automation technologies to improve throughput of disability decisions and reduce the overall backlog.', 'Text and speech analysis, Process optimization and workflow automation, Image and object recognition, Content generation', NULL, NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('10', '10', 'To allow foreign nationals and permanent residents subject to immigration enforcement conditions to report to the CBSA remotely using a smartphone app.', 'The ReportIn app uses facial comparison and geographic data to verify the identity and location of individuals. It includes a cloud-based processing and monitoring system (CRES) that allows CBSA immigration enforcement personnel to monitor, contact, and assess an individual’s reporting facial images, locations, reporting frequency, and compliance history.', 'Facial biometrics, location data, personal identifiers (e.g., Unique Client Identifier), contact information (e.g., email, phone number), device information (e.g., device ID, model, operating system version).', 'Verification of identity and location, compliance assessments, direct messaging with individuals.', 'Foreign nationals and permanent residents subject to immigration enforcement conditions.');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('11', '11', 'The Export Compliance Dashboard provides additional information related to shipments for export to help CBSA Officers perform a risk assessment and identify potential instances of non-compliance in order to select shipments for a physical examination or further review.', 'The tool compares export declaration information received from exporters and shippers against historical records to identify shipments that may have a higher probability of non-compliance and provides an associated risk probability score, and also identifies when specific data points may be missing or anomalous.', 'Export declaration information, historical records', 'Risk probability score, identification of missing or anomalous data points', 'Exporters and shippers');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('12', '12', 'The project seeks to automate the eligibility approval for both the Sponsor and Principal Applicant of routine Family Class overseas spouse and partner applications. The project also streamlines all routine and standard Family Class overseas spouse and partner applications by sorting them based on common characteristics to allow for operational efficiencies.', NULL, NULL, 'The tools automate the assessment of sponsor and principal applicant eligibility approval decisions for certain applications and triages all Family Class overseas spouse and partner applications.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('13', '13', 'The Integrity Trends Analysis Tool (ITAT) analyzes large volumes of data and extracts various risk and fraud patterns within applications containing adverse characteristics.', 'The tool analyzes data to identify risk patterns and does not automate recommendations or decisions. It flags applications for further verification by Risk Assessment Units, which then perform verification activities independently.', 'Data from applications under the Immigration and Refugee Protection Act (IRPA) and Regulations (IRPR).', 'Verification activities results are shared with processing officers to consider in their final decision-making.', 'Applicants of temporary resident programs, including study permit applications, temporary resident visa applications, and temporary foreign worker applications.');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('14', '14', 'Process optimization and workflow automation', 'This project seeks to streamline the eligibility assessment for a subset of IEC WP applications in order to help IRCC decision-makers process applications more efficiently. The IEC WP model triages IEC WP applications by grouping files with similar characteristics based on the legislative, regulatory and contractual requirements for each subprogram and participating country. The model is designed to apply pre-defined triage criteria to triage and identify “light-touch” routine cases where the eligibility portion can receive an automated positive eligibility Assessment.', NULL, 'The system will automate the assessment of the eligibility of a subset of applications submitted for the IEC Working Holiday Program.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('15', '15', 'The Mental Health Benefits would allow Veterans to access coverage for mental health treatment and supports immediately upon application for Disability Benefits for certain mental health conditions, for up to two years or until their disability entitlement decision is granted.', 'Process optimization and workflow automation: Analyzing large data sets to identify and anomalies, cluster patterns, predict outcomes or ways to optimize; and automate specific workflows', 'personal information', NULL, 'Veterans');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('16', '16', 'To improve the efficiency of passport issuance checks through automated business rules that reflect the manual steps currently performed by a passport officer.', 'In 2019, the Canadian Passport Order was amended to authorize the use of automated decision-making, enabling the Passport Program to begin automated processing through the Global Case Management System. Automated decision-making is only used for routine, low risk cases resulting in positive decisions (e.g. adult passport renewals).', 'Personal information of applicants, including identity verification, eligibility validation (e.g., Canadian citizenship), and entitlement confirmation (e.g., any restrictions impacting the right to a passport).', 'Decisions on passport issuance for routine, low risk cases.', 'Applicants for Canadian passports, particularly those applying for routine, low risk renewals.');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('17', '17', 'The Passport Program uses facial recognition technology to support identity authentication, help detect fraud, and prevent passport and travel document issuance to ineligible applicants.', 'Facial recognition technology detects and analyzes facial features for identity verification. It converts facial images into biometric templates for future comparison, performing one-to-many and one-to-one verifications.', 'Facial images of passport applicants', 'List of candidates ranked by similarity score, verification of identity', 'Passport applicants');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('18', '18', NULL, 'PACT aims to identify and apply risk mitigation measures to inbound high-risk air shipments that could contain concealed improvised explosive devices or other threat items prior to loading and departure to Canada. This is achieved through the risk assessment of advanced cargo information from air carriers with the assistance of emerging technologies.', 'shipper and consignee name and address, cargo weight, description and piece count, and air waybill number', 'Requests for Information (RFI), Requests for Screening (RFS) or Do Not Load (DNL) notices.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('19', '19', 'Réduire le temps et les coûts associés à la conduite des entrevues, résoudre les enjeux potentiels relatifs aux biais, et maintenir un degré élevé de structure et de rigueur dans le cadre du processus d’entrevue.', 'La plateforme Knockri permet de mesurer les attributs comportementaux relatifs au rendement des membres du personnel au sein du SCT grâce à une entrevue comportementale structurée qui est administrée et notée automatiquement.', 'Attributs comportementaux des candidatures', 'Évaluation des attributs comportementaux, notes d''entrevue', 'Candidatures aux postes AS-01/AS-02 et EX-01 au sein du SCT');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('20', '20', 'The project involves building a web-based offline, on-premise application that uses AI engines to assist with the transcription and/or translation of audio files collected during investigations.', 'The application will process audio files and generate a transcription and/or translation that will then be reviewed and edited by transcribers/translators prior to disclosure.', 'Input data used in the system is lawfully collected by the RCMP as evidence using various means. It is uploaded to the system, transcribed/translated, and subsequently deleted from the system after the transcription has been downloaded.', 'The output of the system is a text file transcription of the input audio file. The original audio file is needed by verify the accuracy of the text transcription by a transcriber/translator.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('21', '21', NULL, 'Site Web central et simple permettant aux Canadiens de soumettre des demandes d''AIPRP', NULL, NULL, NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('22', '22', 'Faciliter une utilisation plus efficace des ressources d’IRCC dans le traitement des demandes au moyen d’économies d’échelle, en aidant à gérer le nombre croissant de demandes et en permettant au personnel de se concentrer davantage sur les tâches plus complexes, comme les évaluations en attente.', 'L’OSAA est un soutien du traitement qui aide le personnel à effectuer des tâches administratives liées aux demandes d’immigration, y compris la correspondance d’éléments de données et la création de messages en bloc. Deux des modules entrent dans le cadre de la Directive sur la prise de décision automatisée du Conseil du Trésor.', 'Renseignements biographiques du client, renseignements biographiques tirés d’inscriptions de données biométriques non rattachés aux demandes (module des données biométriques), renseignements biographiques tirés d’examens médicaux aux fins de l’immigration effectués et non rattachés à des demandes (module médicale).', 'Recommandations de correspondances entre les inscriptions de données biométriques et les demandes, ainsi que les examens médicaux aux fins de l’immigration et les demandes.', 'Clients d''IRCC impliqués dans des processus d''immigration nécessitant des examens médicaux et des inscriptions biométriques.');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('23', '23', 'Faciliter l’utilisation plus efficace des ressources d’IRCC dans le traitement des demandes de visa, aider à gérer le nombre croissant de demandes de visa de résident temporaire, et améliorer les délais de traitement et l’identification de cas complexes.', 'Ce projet vise à simplifier l’évaluation de l’admissibilité pour toutes les demandes de visa de résident temporaire (visa de visiteur) présentées depuis l’étranger afin d’aider les décideurs d’IRCC à traiter les demandes plus efficacement. Le système d’analyse avancée des données cerne les demandes ordinaires qui feront l’objet d’un traitement simplifié et trie les demandes dans différents volets, selon leur niveau de complexité. Lorsqu’une demande est jugée ordinaire aux fins du traitement simplifié, l’analyse avancée des données est utilisée pour déterminer uniquement si le demandeur est admissible, alors que les demandes plus complexes sont attribuées à des agents afin qu’ils effectuent le traitement manuel régulier et prennent une décision. Le système rend uniquement des décisions favorables concernant l’admissibilité pour les demandes ordinaires. Il ne rend pas de décisions défavorables et ne réalise pas d’évaluation pour vérifier s’il y a interdiction de territoire. Toutes les demandes sont envoyées à un agent d’immigration pour l’évaluation visant à vérifier s’il y a interdiction de territoire, et les agents doivent examiner tous les renseignements pertinents au dossier lors du traitement des demandes, y compris les renseignements fournis dans les documents supplémentaires. Les agents prennent la décision définitive concernant toutes les demandes.', 'Renseignements personnels', 'Décisions favorables concernant l’admissibilité pour les demandes ordinaires', 'Demandeurs de visa de résident temporaire');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('24', '24', 'Optimisation des processus et automatisation des flux de travail', 'Ce projet vise à simplifier l’évaluation de la recevabilité pour toutes les demandes de fiche de visiteurs afin d’aider les décideurs d’IRCC à traiter les demandes plus efficacement. Le système avancé d’analyse de données identifie les demandes de routine pour un traitement rationalisé. Lorsque le système trouve ces demandes, il peut décider qu’un demandeur est recevable, avant d’envoyer le dossier à un agent pour décider si le demandeur est interdit de territoire et prendre la décision finale.', 'Données de cas antérieurs d’IRCC', 'Le système peut automatiser l''approbation de la partie recevabilité de certaines demandes de fiche du visiteur. Pour ces demandes, le système détermine seulement si le demandeur est recevable avant que la demande ne soit envoyée à un agent pour vérifier s’il y a interdiction de territoire.', 'Les clients demandant des fiches de visiteur, qui ne demandent pas le statut de réfugié, la résidence permanente ou la citoyenneté, et n’ont pas le droit d’étudier ou de travailler au Canada.');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('25', '25', NULL, 'Le réexamen des demandes nécessitant un recalcul des prestations de l''assurance-emploi (AE) implique une analyse approfondie et une réévaluation complète en réponse à de nouvelles informations ou à des changements de circonstances. L''objectif principal est de garantir des calculs de prestations précis, qu''ils résultent en un paiement en trop, un paiement insuffisant ou aucun changement.', 'Données de production de l''AE', 'Augmentation du taux de prestations; Diminution du taux de prestations; Aucune modification du taux de prestations.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('26', '26', 'ArriveCAN est une plateforme numérique qui sert à recueillir des renseignements sur les voyages et la santé liés à la COVID-19 auprès des personnes qui se rendent au Canada.', 'En automatisant la numérisation de la preuve de vaccination des voyageurs à l’aide de la technologie d’outil de reconnaissance optique des caractères (ROC).', 'Rencontres personnelles comme données d’entrée', 'Les preuves de vaccination analysées aident à déterminer si un voyageur est admissible à entrer au Canada et les exigences de quarantaine ou autres exigences auxquelles il peut être assujetti après son entrée.', 'Voyageurs entrant au Canada');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('27', '27', 'Automatiser le traitement des demandes pour certains visas de résident temporaire et permis de travail faites dans le cadre de l''Autorisation de voyage d''urgence Canada-Ukraine (AVUCU).', 'Optimisation des processus et automatisation des flux de travail: Analyser de vastes jeux de données pour déterminer et corriger les anomalies, les modèles de grappes, prévoir les résultats ou les façons d''optimiser; et d''automatiser des flux de travail spécifique.', 'Renseignements personnels', 'Décisions de recevabilité favorables, décisions d''interdiction de territoire favorables et approbations concernant certaines demandes de visa de résident temporaire et de permis de travail.', 'Clients de l''immigration');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('28', '28', 'Optimisation des processus et automatisation des flux de travail', 'Ce projet a pour but de simplifier l’évaluation de la recevabilité des demandes de permis de travail postdiplôme (PTPD) et des autres demandes de permis de travail au Canada afin d’aider les décideurs d’IRCC à traiter les demandes de manière plus efficace.', NULL, 'Les outils peuvent uniquement déterminer que le demandeur est recevable. Les demandes plus complexes sont confiées à des agents qui les traitent manuellement et prennent une décision, comme auparavant.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('29', '29', NULL, 'Le projet vise à accroître notre utilisation des technologies d’automatisation afin d’améliorer le traitement des décisions en matière de prestations d’invalidité et de réduire l’arriéré global.', 'renseignements personnels', NULL, NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('30', '30', NULL, 'Le système d’automatisation permet de simplifier le traitement des deux parties des demandes de réfugiés parrainés par le secteur privé : la partie concernant le parrainage et la partie concernant le réfugié. Lors de l’examen d’une demande, le système numérisera d’abord la partie concernant le parrainage afin de détecter les cas courants qui peuvent être approuvés automatiquement. Toutes les parties concernant le parrainage qui ne sont pas automatiquement approuvées par le système seront examinées par un agent lors du processus manuel actuel. Pour la deuxième partie de la demande, soit celle concernant le dossier du demandeur d’asile, le système permet de trier et d’attribuer des demandes aux agents en fonction de leur expertise et des capacités des bureaux de migration à l’étranger au sein desquels ils travaillent.', 'renseignements personnels', 'Le système automatisera les approbations de la partie concernant le parrainage pour ce qui est de la résidence permanente dans le cadre du Programme de parrainage privé de réfugiés (PPPR) pour certaines demandes courantes. Les refus ne seront pas automatisés.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('31', '31', 'Surveiller et appliquer les conditions imposées aux personnes au Canada en vertu de la Loi sur l’immigration et la protection des réfugiés (LIPR) et du Règlement sur l’immigration et la protection des réfugiés (RIPR).', 'Une application de téléphone intelligent accessible au public, JeMePrésente, utilisée sur une base volontaire, où les personnes soumettent des rapports à l’aide d’un dispositif mobile ou téléphone intelligent et d’images faciales comme moyen d’authentifier l’identité des personnes. Les données biométriques faciales et la localisation des personnes, fournies par les capteurs ou le GPS du dispositif mobile ou du téléphone intelligent, sont enregistrées lorsqu’elles effectuent une déclaration au moyen de l’application JeMePrésente, et sont envoyées au système infonuagique de traitement et de surveillance, SREC.', 'Données biométriques faciales, localisation des personnes, prénom et nom de famille, identificateur unique du client (IUC), adresse de courriel personnelle, numéro de téléphone, renseignements sur l’emploi (si applicable), photos faciales, texte du rapport ponctuel, emplacement, ID d’appareil, modèle de l’appareil, version du système d’exploitation de l’appareil, message d’erreur, renseignements de localisation.', 'Rapports de conformité, évaluations de risque, décisions de détention.', 'Ressortissants étrangers et résidents permanents soumis à des conditions d''exécution de la législation sur l''immigration.');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('32', '32', NULL, 'Le Tableau de bord de conformité des exportations est un outil qui fournit des informations supplémentaires sur les expéditions destinées à l’exportation. Il vise à aider les agents de l''ASFC à évaluer les risques et à identifier les cas potentiels de non conformité afin de sélectionner les expéditions devant être renvoyées pour un examen physique ou nécessitant une évaluation plus approfondie.', 'Les données d’entrée, leur source et leur méthode de collecte', 'Le résultat produit par le système et toute information pertinente nécessaire pour l’interpréter dans le contexte de la décision administrative', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('33', '33', 'Optimisation des processus et automatisation des flux de travail, Évaluation des risques', 'Le projet vise à automatiser l’approbation de la recevabilité, pour le répondant et le demandeur principal, des demandes courantes d''époux et de conjoints de la catégorie du regroupement familial à l’étranger. Le projet simplifie également toutes les demandes courantes et standard de la catégorie du regroupement familial à l’étranger en les triant en fonction des caractéristiques communes, afin de favoriser l’efficacité opérationnelle.', 'Données soumises par les clients dans leur demande', 'Les outils trient les demandes et automatiseront les décisions d’approbation de la recevabilité pour certaines demandes.', 'Clients du Programme de regroupement familial d’IRCC');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('34', '34', 'LOGICIEL déjà utilisé – Outil développé pour catégoriser et classer les images et les vidéos d’exploitation d’enfants.', 'Il intègre les contenus multimédias provenant des éléments de preuve saisis et des transmissions des partenaires (NCMEC, Cyberaide et d’autres organismes d’application de la loi) et il présente tous les contenus multimédias et les métadonnées intégrées connexes (données EXIF, etc.) dans un espace de travail où les catégories conformes à l’art. 163 du Code criminel peuvent être appliquées, où les contenus multimédias peuvent être regroupés à l’aide de divers filtres et où une précatégorisation est effectuée dans les bases de données des condensés du matériel connu.', 'Contenus multimédias, métadonnées intégrées, données EXIF', 'Catégorisation des images et vidéos, précatégorisation dans les bases de données, exportation des condensés et métadonnées', 'Enfants victimes d''exploitation');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('35', '35', 'Analyser de grands volumes de données et extraire divers motifs de risque et de fraude', 'L’Outil d’analyse des tendances en matière d’intégrité (OATI) analyse de grands volumes de données et extrait divers motifs de risque et de fraude des demandes présentant des caractéristiques défavorables, comme des conclusions d’interdiction de territoire (p. ex. criminalité et fausses déclarations) et d’autres mesures administratives ou d’exécution de la loi découlant de la Loi sur l’immigration et la protection des réfugiés (LIPR) et du Règlement sur l’immigration et la protection des réfugiés (RIPR).', NULL, NULL, NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('36', '36', 'Optimisation des processus et automatisation des flux de travail', 'Ce projet vise à simplifier l’évaluation de la recevabilité d’un sous-ensemble de demandes de permis de travail d’EIC pour aider les décideurs d’IRCC à traiter plus efficacement les demandes. Le modèle de permis de travail d’EIC permet de trier les demandes en regroupant les dossiers qui présentent des caractéristiques similaires en fonction des exigences réglementaires, contractuelles ou prévues par la loi de chaque sous-programme et de chaque pays participant. Le modèle est conçu pour appliquer des critères de tri prédéfinis afin de trier et d’identifier les cas de routine « légers » pour lesquels la partie relative à la recevabilité peut être soumise à une évaluation automatisée selon des règles opérationnelles préexistantes uniquement pour le programme Vacances-Travail d’EIC.', NULL, 'Le système automatisera l’évaluation de la recevabilité d’un sous-ensemble de demandes soumises pour le programme Vacances-Travail d’EIC.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('37', '37', NULL, 'Les avantages pour la santé mentale permettraient aux vétérans d’accéder au traitement en santé mentale et au soutien dont ils ont besoin dès qu’ils présentent leur demande de prestations d’invalidité pour certains problèmes de santé mentale. Cette couverture pourrait s’échelonner sur une période allant jusqu’à deux ans ou jusqu’à ce que soit rendue une décision établissant leur admissibilité.', 'renseignements personnels', NULL, 'vétérans');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('38', '38', NULL, 'Un système a été conçu pour identifier l’utilisation abusive ou frauduleuse du programme SV en appliquant des techniques de priorisation et d’optimisation de la charge de travail avec l’objectif de se concentrer sur les cas prioritaires.', 'informations de voyageurs de l’Agence des services frontaliers du Canada (ASFC), système de pensions de la SV, et du registre du NAS', 'Le système filtrera les données en fonction des critères du programme et résumera les données en groupes avec une étiquette de regroupement et fournira un résumé par groupe.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('39', '39', NULL, 'Le Décret sur les passeports canadiens a été modifié en 2019 afin d’autoriser le recours à la prise de décisions automatisée, ce qui a permis au Programme de passeport d’entreprendre l’automatisation du traitement au moyen du Système mondial de gestion des cas. Le processus décisionnel automatisé est utilisé seulement pour les demandes de routine, pour lesquelles les risques sont faibles et qui débouchent sur des décisions positives (p. ex. le renouvellement des passeports pour adultes). Les cas complexes, les demandes initiales de passeports, les demandes de passeports pour enfants et d’autres demandes seront acheminés à un agent qui en fera lui-même l’évaluation et qui prendra une décision. Toute décision visant à refuser, à révoquer ou à annuler un passeport continuera d’être prise par un agent.', 'Informations personnelles des demandeurs', 'Décisions sur la délivrance des passeports', 'Demandeurs de passeport canadien');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('40', '40', 'Amélioration de la qualité générale des décisions, réduction des coûts de transaction d''un programme existant, exécution de tâches que les humains ne sont pas en mesure d''accomplir dans un délai raisonnable, utilisation d''approches novatrices', 'Le système de reconnaissance faciale convertit les images faciales en des modèles biométriques faciaux qui peuvent être stockés dans le système et utilisés ultérieurement aux fins de comparaison. Il effectue des comparaisons ''un à plusieurs'' (1:N) et ''un à un'' (1:1) pour l''identification et la vérification de l''identité.', 'Données biométriques faciales des requérants adultes, modèles biométriques d''anciens requérants, modèles associés à des personnes dont l''admissibilité doit être examinée', 'Liste de candidats classés selon une cote de similarité, vérification de l''identité des requérants', 'Requérants adultes de passeport canadien');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('41', '41', 'Le ciblage du fret aérien préalable au chargement (CFAPC) vise à déceler les envois de fret aérien à haut risque, qui pourraient contenir des engins explosifs improvisés dissimulés ou d’autres éléments de menace, avant le chargement du fret et le départ vers le Canada, et à leur appliquer des mesures d’atténuation des risques.', 'Le système de CFAPC triera et classera les données et appliquera un algorithme de risque pour signaler à l’analyste de CFAPC les envois pouvant présenter un risque potentiellement élevé. Les envois dont les caractéristiques relèvent d’un scénario prédéfini de faible risque sont évalués automatiquement et ne sont pas soumis à l’examen d’un analyste de CFAPC. Inversement, les envois qui ne correspondent pas à ces paramètres sont présentés aux analystes de CFAPC, qui peuvent alors décider d''appliquer une mesure d’atténuation des risques à un envoi de fret aérien avant qu’il ne soit chargé à bord d’un avion à destination du Canada.', 'Cette information comprend le nom et l’adresse de l’expéditeur et du destinataire, le poids, la description et le nombre d’articles de fret, ainsi que le numéro de la lettre de transport aérien.', 'Les envois dont les caractéristiques relèvent d’un scénario prédéfini de faible risque sont évalués automatiquement et ne sont pas soumis à l’examen d’un analyste de CFAPC. Inversement, les envois qui ne correspondent pas à ces paramètres sont présentés aux analystes de CFAPC, qui peuvent alors décider d''appliquer une mesure d’atténuation des risques à un envoi de fret aérien avant qu’il ne soit chargé à bord d’un avion à destination du Canada.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('42', '42', NULL, 'La Direction générale de la dirigeante principale des données (DGDPD), les Services de versement des prestations (SVP) de l’assurance-emploi (AE) et la Direction générale de l’innovation, de l’information et de la technologie (DGIIT) mettent en oeuvre une solution d’intelligence artificielle (IA) et d''apprentissage automatique qui interprétera et évaluera les commentaires en texte libre saisis par les employeurs quand les relevés d’emploi (RE) sont émis. Selon des règles opérationnelles très précises, l’IA évaluera et prévoira des mesures simples (c.-à-d. enregistrer ou ignorer les commentaires ou prévoir un motif de cessation d’emploi [MCE] différent). Les mesures prises à la suite de prédictions de l’IA seront enregistrées dans les notes interprétatives internes utilisées dans le traitement des demandes d''AE. Le document initial (RE) ne sera pas modifié.', 'les données d’entrée, leur source et leur méthode de collecte', 'le résultat produit par le système et toute information pertinente nécessaire pour l’interpréter dans le contexte de la décision administrative', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('43', '43', NULL, 'Afin de réduire l’inventaire des prestations d’Assurance-Emploi à recalculer, un modèle de Machine Learning a été utilisé à des fins de classification. Le modèle classifie les demandes en trois catégories: Augmentation des Taux de prestations, Diminution des Taux de prestations, Aucun changement des Taux de prestations.', 'Renseignements personnels comme données d’entrée', 'Classification des demandes en: Augmentation des Taux de prestations, Diminution des Taux de prestations, Aucun changement des Taux de prestations.', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('44', '44', 'Optimisation des processus et automatisation des flux de travail', 'Le PAR-MVA a pour objectif de vérifier les informations déclarées par les emprunteurs lors de leur demande au PAR, en les comparant aux renseignements sur les contribuables fournis par l’Agence du revenu du Canada (ARC).', 'Informations déclarées par les emprunteurs, renseignements sur les contribuables fournis par l’Agence du revenu du Canada (ARC)', 'Approbation ou refus du PAR', 'Emprunteurs du Programme d''aide au remboursement');

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('45', '45', 'Un ensemble d’algorithmes et de règles commerciales pour prioriser les cas du PTET pour inspection en fonction de l’existence et de la gravité des facteurs de risque établis.', 'Évaluation des risques: Analyser de volumineux jeux de données pour déterminer les tendances et recommander des mesures et, dans certains cas, déclencher la prise de mesures précises. Optimisation des processus et automatisation des flux de travail: Analyser de vastes jeux de données pour déterminer et corriger les anomalies, les modèles de grappes, prévoir les résultats ou les façons d''optimiser; et d''automatiser des flux de travail spécifique.', 'les données d’entrée, leur source et leur méthode de collecte', 'le résultat produit par le système et toute information pertinente nécessaire pour l’interpréter dans le contexte de la décision administrative', NULL);

INSERT INTO systems (system_id, project_id, system_purpose, system_description, data_inputs, decision_outputs, affected_population)
VALUES ('46', '46', 'Using artificial intelligence (AI) to automate candidate evaluations in the staffing process''s assessment phase', 'Knockri can measure behavioural attributes related to employee performance within the TBS through a structured behavioural interview that is administered and scored automatically.', 'Behavioural attributes of job candidates', 'Assessment scores', 'Job candidates for AS-01/AS-02 and EX-01 positions within the Treasury Board Secretariat');

